/// Parse a static event payload from raw event hash and bytes.
///
/// This is a convenience function that combines hash lookup with payload parsing.
pub fn parse_static_event(event_hash: i32, payload_bytes: &[u8]) -> Result<StaticEventPayload, deku::DekuError> {
    match StaticEventType::from_hash(event_hash) {
        Some(event_type) => event_type.parse_payload(payload_bytes),
        None => Ok(StaticEventPayload::Unknown {
            event_hash,
            payload: payload_bytes.to_vec(),
        }),
    }
}

